package com.google.gson.internal.bind;
import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import com.google.gson.JsonNull;
import com.google.gson.JsonObject;
import com.google.gson.JsonPrimitive;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.MalformedJsonException;
import java.io.IOException;
import java.io.Reader;
import java.util.Arrays;
import java.util.Iterator;
import java.util.Map;

import static org.junit.jupiter.api.Assertions.*;

import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

public class JsonTreeReaderTest {

  private JsonTreeReader reader;

  @BeforeEach
  public void setUp() throws Exception {
    // Mock JsonElement input for constructor (can be null since we won't use it directly)
    reader = new JsonTreeReader(null);

    // Setup internal state for testing endArray
    // stackSize = 2 (to allow stack pops and pathIndices increment)
    setField(reader, "stackSize", 2);

    // Initialize stack with dummy objects (not null) to avoid NullPointerException on popStack
    Object[] stack = new Object[32];
    stack[0] = new Object();
    stack[1] = new Object();
    setField(reader, "stack", stack);

    // Initialize pathIndices with zeroes
    int[] pathIndices = new int[32];
    pathIndices[0] = 0;
    pathIndices[1] = 0;
    setField(reader, "pathIndices", pathIndices);
  }

  @Test
  public void testEndArray_normal() throws Exception {
    // Setup stack and stackSize again to ensure popStack works
    Object[] stack = new Object[32];
    stack[0] = new Object();
    stack[1] = new Object();
    setField(reader, "stack", stack);
    setField(reader, "stackSize", 2);

    // Call endArray via reflection
    invokePrivateVoidMethod(reader, "endArray");

    // Verify pathIndices[stackSize - 1] incremented by 1
    int[] pathIndices = getField(reader, "pathIndices");
    int stackSize = getField(reader, "stackSize");
    assertEquals(1, pathIndices[stackSize - 1]);
  }

  @Test
  public void testEndArray_stackSizeZero_noIncrement() throws Exception {
    // Set stackSize to 0 to test no increment branch
    setField(reader, "stackSize", 0);

    // Setup stack with dummy objects so popStack does not fail
    Object[] stack = new Object[32];
    stack[0] = new Object();
    setField(reader, "stack", stack);

    // Call endArray via reflection
    invokePrivateVoidMethod(reader, "endArray");

    int[] pathIndices = getField(reader, "pathIndices");
    // Since stackSize is 0, no increment should occur, all zeros
    for (int i = 0; i < pathIndices.length; i++) {
      assertEquals(0, pathIndices[i]);
    }
  }

  @Test
  public void testEndArray_expectThrows() throws Exception {
    // Instead of subclassing final JsonTreeReader, use a spy-like approach by reflection to replace expect method
    // Since expect is private, we cannot override it, so we create a helper class to invoke endArray but simulate expect throwing

    JsonTreeReader throwingReader = new JsonTreeReader(null);

    // Setup stack and stackSize so popStack would work if called
    Object[] stack = new Object[32];
    stack[0] = new Object();
    stack[1] = new Object();
    setField(throwingReader, "stack", stack);
    setField(throwingReader, "stackSize", 2);

    // Use a proxy approach: replace the expect method temporarily by reflection to throw exception
    // Since expect is private and final class, we can't override, so we replace the method to throw via java.lang.reflect.Proxy is not possible
    // Instead, we can use a subclass of JsonReader and a custom JsonTreeReader that delegates and overrides expect - but class is final
    // So, we use reflection to replace the method temporarily via MethodHandles or use a wrapper method to simulate expect throwing

    // Instead, we can test that endArray throws if expect throws by invoking expect method directly with wrong token
    // So call expect with a wrong token that will throw

    // Call expect with wrong token via reflection to throw
    Exception thrown = assertThrows(Exception.class, () -> {
      invokePrivateVoidMethod(throwingReader, "expect", JsonToken.BEGIN_OBJECT);
    });

    // Now test that endArray throws as well by invoking endArray after setting expect to throw
    // We simulate expect throwing by temporarily replacing expect method via reflection is complex,
    // so we just test that when expect throws, endArray throws as well by invoking endArray with corrupted state.

    // To simulate expect throwing inside endArray, we can use a subclass of JsonReader with overridden expect - but class is final, so not possible.

    // So, as a workaround, we invoke endArray and expect it to throw if expect throws.
    // We will forcibly corrupt the stack so expect throws.

    // For example, set stackSize to 0 and call endArray, expect it to throw MalformedJsonException or IllegalStateException

    setField(throwingReader, "stackSize", 0);
    setField(throwingReader, "stack", new Object[32]);

    IllegalStateException thrown2 = assertThrows(IllegalStateException.class, () -> {
      invokePrivateVoidMethod(throwingReader, "endArray");
    });

    // The exact message may vary; just check exception type
    assertNotNull(thrown2);
  }

  // Helper to get private field via reflection
  @SuppressWarnings("unchecked")
  private <T> T getField(Object target, String name) throws Exception {
    Field field = JsonTreeReader.class.getDeclaredField(name);
    field.setAccessible(true);
    return (T) field.get(target);
  }

  // Helper to set private field via reflection
  private void setField(Object target, String name, Object value) throws Exception {
    Field field = JsonTreeReader.class.getDeclaredField(name);
    field.setAccessible(true);
    field.set(target, value);
  }

  // Helper to invoke private void method with one parameter
  private void invokePrivateVoidMethod(Object target, String methodName, Object param) throws Exception {
    Method method = JsonTreeReader.class.getDeclaredMethod(methodName, param.getClass());
    method.setAccessible(true);
    method.invoke(target, param);
  }

  // Helper to invoke private void method with no parameters
  private void invokePrivateVoidMethod(Object target, String methodName) throws Exception {
    Method method = JsonTreeReader.class.getDeclaredMethod(methodName);
    method.setAccessible(true);
    method.invoke(target);
  }
}
